import { useState, useEffect } from "react";
import { useSelector } from "react-redux";
import { toast } from "react-toastify";

function AdminPanel() {
  const [users, setUsers] = useState([]);
  const [grades, setGrades] = useState([]);
  const user = useSelector((state) => state.auth.user);

  useEffect(() => {
    fetch("http://localhost:3001/users")
      .then((res) => res.json())
      .then((data) => setUsers(data))
      .catch((error) => toast.error("Ошибка загрузки пользователей"));
    fetch("http://localhost:3001/grades")
      .then((res) => res.json())
      .then((data) => setGrades(data))
      .catch((error) => toast.error("Ошибка загрузки оценок"));
  }, []);

  async function handleBanToggle(userId, isBanned) {
    try {
      const response = await fetch(`http://localhost:3001/users/${userId}`, {
        method: "PATCH",
        headers: { "Content-Type": "application/json" },
        body: JSON.stringify({ isBanned: !isBanned }),
      });
      if (response.ok) {
        setUsers(
          users.map((u) =>
            u.id === userId ? { ...u, isBanned: !isBanned } : u
          )
        );
        toast.success(`Пользователь ${isBanned ? "разбанен" : "забанен"}!`);
      } else {
        toast.error("Не удалось изменить статус бана");
      }
    } catch (error) {
      toast.error("Сетевая ошибка");
    }
  }

  async function handleRoleChange(userId, newRole) {
    try {
      const response = await fetch(`http://localhost:3001/users/${userId}`, {
        method: "PATCH",
        headers: { "Content-Type": "application/json" },
        body: JSON.stringify({ role: newRole }),
      });
      if (response.ok) {
        setUsers(
          users.map((u) => (u.id === userId ? { ...u, role: newRole } : u))
        );
        toast.success("Роль изменена!");
      } else {
        toast.error("Не удалось изменить роль");
      }
    } catch (error) {
      toast.error("Сетевая ошибка");
    }
  }

  const averageScore =
    grades.length > 0
      ? (
          grades.reduce((sum, grade) => sum + grade.score, 0) / grades.length
        ).toFixed(2)
      : "Нет данных";

  if (user?.role !== "admin") {
    return <div className="container mt-5"><h1>Доступ запрещен</h1></div>;
  }

  return (
    <div className="container mt-5">
      <h1 className="mb-4">Панель администратора</h1>
      <h3>Управление пользователями</h3>
      <table className="table table-striped mb-4">
        <thead>
          <tr>
            <th>Имя</th>
            <th>Email</th>
            <th>Роль</th>
            <th>Статус</th>
            <th>Действия</th>
          </tr>
        </thead>
        <tbody>
          {users.map((u) => (
            <tr key={u.id}>
              <td>{u.name}</td>
              <td>{u.email}</td>
              <td>
                <select
                  value={u.role}
                  onChange={(e) => handleRoleChange(u.id, e.target.value)}
                  className="form-select"
                >
                  <option value="admin">Админ</option>
                  <option value="teacher">Учитель</option>
                  <option value="student">Студент</option>
                </select>
              </td>
              <td>{u.isBanned ? "Забанен" : "Активен"}</td>
              <td>
                <button
                  onClick={() => handleBanToggle(u.id, u.isBanned)}
                  className={`btn btn-sm ${
                    u.isBanned ? "btn-success" : "btn-danger"
                  }`}
                >
                  {u.isBanned ? "Разбанить" : "Забанить"}
                </button>
              </td>
            </tr>
          ))}
        </tbody>
      </table>
      <h3>Средний балл всех студентов</h3>
      <p><strong>Средний балл:</strong> {averageScore}</p>
    </div>
  );
}

export default AdminPanel;
